@namespace Lumeo
@typeparam TItem
@attribute [CascadingTypeParameter(nameof(TItem))]
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.ToastService Toast

@{
    var context = new DataGridContext<TItem>(
        Columns: _orderedColumns.Where(c => c.Visible).ToList().AsReadOnly(),
        DisplayedItems: _displayedItems.AsReadOnly(),
        SelectedItems: _selectedItems.AsReadOnly(),
        Sorts: _sorts,
        Filters: _filters,
        GlobalSearch: _globalSearch,
        CurrentPage: _currentPage,
        PageSize: PageSize,
        TotalCount: EffectiveTotalCount,
        SelectionMode: SelectionMode,
        EditMode: EditMode,
        IsLoading: IsLoading || (_serverService?.IsLoading ?? false),
        RowReorderable: RowReorderable,
        RowContextMenuEnabled: RowContextMenu is not null,
        OnRowClick: OnRowClick,
        OnRowDoubleClick: OnRowDoubleClick,
        OnSort: EventCallback.Factory.Create<SortDescriptor>(this, HandleSort),
        OnFilter: EventCallback.Factory.Create<FilterDescriptor>(this, HandleFilter),
        OnSelectionChanged: EventCallback.Factory.Create<TItem>(this, HandleSelectionChanged),
        OnCellEdit: OnCellEdit,
        IsRowSelected: IsRowSelected,
        IsRowExpanded: IsRowExpanded,
        IsRowEditing: IsRowEditing,
        ToggleSelection: ToggleSelection,
        SelectAll: SelectAll,
        ClearSelection: ClearSelection,
        ToggleRowExpand: ToggleRowExpand,
        StartRowEdit: StartRowEdit,
        CancelRowEdit: CancelRowEdit,
        CommitRowEdit: CommitRowEditAsync,
        GetEditValue: GetEditValue,
        SetEditValue: SetEditValue,
        RowClass: RowClass,
        RowStyle: RowStyle,
        PinnedLeftOffsets: ComputePinnedLeftOffsets(),
        PinnedRightOffsets: ComputePinnedRightOffsets(),
        GroupedSections: _groupedSections.Count > 0 ? _groupedSections.AsReadOnly() : null,
        GroupBy: GroupBy,
        IsGrouped: !string.IsNullOrEmpty(GroupBy) && _groupedSections.Count > 0,
        IsGroupExpanded: IsGroupExpanded,
        ToggleGroupExpand: ToggleGroupExpand,
        Culture: EffectiveCulture
    );
}

@{
    RenderFragment gridRoot = @<div data-slot="datagrid" class="@RootCssClass" style="@HeightStyle" @attributes="AdditionalAttributes">

        @* Declarative column definitions *@
        <div class="hidden">@ChildContent</div>

        @if (_serverService?.Error is not null)
        {
            <div class="flex items-center gap-2 px-4 py-2.5 border-b border-destructive/30 bg-destructive/10 text-sm">
                <Blazicon Svg="Lucide.CircleAlert" class="h-4 w-4 shrink-0 text-destructive" />
                <span class="flex-1 text-destructive-text">@L["DataGrid.ErrorLoadingData", _serverService.Error ?? ""]</span>
                <button type="button"
                        class="text-xs text-destructive underline hover:no-underline"
                        @onclick="@(async () => { _serverService!.ClearError(); await RequestServerData(); })">
                    @L["DataGrid.Retry"]
                </button>
            </div>
        }

        @if (ShowToolbar)
        {
            <DataGridToolbar TItem="TItem"
                             SearchText="@_globalSearch"
                             SearchTextChanged="HandleGlobalSearch"
                             RegisteredContent="@RegisteredToolbarContent"
                             OnColumnToggle="HandleColumnVisibilityChanged"
                             OnColumnReorder="HandleColumnReorder"
                             OnExport="HandleExport"
                             OnRemoveFilter="RemoveFilter"
                             SelectedItems="_selectedItems"
                             AllItems="@(ServerMode ? _displayedItems : _processedItems)"
                             EffectiveColumns="EffectiveColumns.AsReadOnly()"
                             EnableLayoutPersistence="EnableLayoutPersistence"
                             OnSaveLayout="HandleSaveLayout"
                             OnResetLayout="HandleResetLayout"
                             GlobalLayouts="GlobalLayouts"
                             OnSaveNamedLayout="HandleSaveNamedLayout"
                             OnDeleteNamedLayout="OnDeleteNamedLayout"
                             OnApplyNamedLayout="HandleApplyNamedLayout"
                             LayoutStorageKey="LayoutStorageKey"
                             OnError="OnError"
                             Expandable="Expandable"
                             IsExpanded="_isExpanded"
                             OnToggleExpanded="ToggleExpanded"
                             ShowSearch="ShowSearch"
                             ShowColumnChooser="ShowColumnChooser"
                             ShowExport="ShowExport"
                             ExportFormats="ExportFormats" />
        }

        @if (_contextMenuVisible)
        {
            <div id="@_contextMenuId"
                 class="fixed z-50 min-w-[160px] rounded-md border border-border/40 bg-popover p-1 shadow-md"
                 style="left: @(_contextMenuX)px; top: @(_contextMenuY)px;"
                 @onclick:stopPropagation="true">
                @if (RowContextMenu is not null && _contextMenuItem is not null)
                {
                    @RowContextMenu(_contextMenuItem)
                }
            </div>
        }

        <div class="overflow-auto flex-1" @onclick="CloseContextMenu">
            <table class="w-full caption-bottom text-sm">
                <DataGridHeader TItem="TItem"
                                HasDetailTemplate="@(DetailTemplate is not null)"
                                ActiveFilterColumn="@_activeFilterColumn"
                                OnFilterToggle="HandleFilterToggle"
                                OnFilterApply="HandleFilterApply"
                                Reorderable="Reorderable"
                                OnColumnReorder="HandleColumnReorder" />

                <DataGridBody TItem="TItem"
                              DetailTemplate="DetailTemplate"
                              EmptyContent="EmptyContent"
                              UseVirtualization="@UseVirtualization"
                              HasDetailTemplate="@(DetailTemplate is not null)"
                              SkeletonRowCount="@PageSize"
                              OnContextMenu="@(args => HandleContextMenu(args.Item1, args.Item2, args.Item3))" />

                <DataGridFooter TItem="TItem"
                                AllItems="@_processedItems"
                                HasDetailTemplate="@(DetailTemplate is not null)" />
            </table>
        </div>

        @if (ShowPagination && !IsLoading)
        {
            <DataGridPagination TItem="TItem"
                                PageChanged="HandlePageChanged"
                                PageSizeChanged="HandlePageSizeChanged" />
        }
    </div>;
}

<CascadingValue Value="this" IsFixed="true">
<CascadingValue Value="_dragState" IsFixed="true">
<CascadingValue Value="context" IsFixed="false">
<CascadingValue Value="_toolbarContext" IsFixed="false">
    @if (_isExpanded)
    {
        <div class="fixed inset-0 lumeo-datagrid-fullscreen-backdrop"
             style="z-index: 99;"
             aria-hidden="true"
             @onclick="ToggleExpanded"></div>
        <div class="fixed bg-background flex flex-col border border-border/60 rounded-xl shadow-2xl overflow-hidden lumeo-datagrid-fullscreen lumeo-datagrid-fullscreen-panel"
             style="z-index: 100; inset: 2.5rem;"
             role="dialog"
             aria-modal="true"
             aria-label="@(FullscreenTitle ?? "Expanded data grid")"
             tabindex="-1"
             @ref="_fullscreenRef"
             @onkeydown="HandleFullscreenKeyDown">
            @* Title strip — only shown when FullscreenTitle is set. The X was removed because the toolbar
               already renders a Minimize icon (DataGridToolbarFullscreen) that does the same thing. Users
               without that tool in a custom ToolbarContent can still press Esc. *@
            @if (!string.IsNullOrEmpty(FullscreenTitle))
            {
                <div class="flex items-center border-b border-border/40 px-5 py-2.5 shrink-0 bg-muted/30">
                    <Heading Level="3" Class="text-sm font-semibold m-0 tracking-tight">@FullscreenTitle</Heading>
                </div>
            }
            @* No extra padding — the grid component carries its own borders/rounded corners and fills the
               remaining modal height via CSS (see `.lumeo-datagrid-fullscreen-panel [data-slot=datagrid]`). *@
            <div class="flex-1 min-h-0 flex flex-col">
                @gridRoot
            </div>
        </div>
    }
    else
    {
        @gridRoot
    }
</CascadingValue>
</CascadingValue>
</CascadingValue>
</CascadingValue>

@code {
    // --- Data ---
    [Parameter] public IEnumerable<TItem>? Items { get; set; }
    [Parameter] public List<DataGridColumn<TItem>>? Columns { get; set; }

    // --- Appearance ---
    [Parameter] public bool Striped { get; set; }
    [Parameter] public bool Bordered { get; set; }
    [Parameter] public bool Compact { get; set; }
    [Parameter] public bool Hoverable { get; set; } = true;
    [Parameter] public string? Height { get; set; }

    // --- Features ---
    [Parameter] public DataGridSelectionMode SelectionMode { get; set; } = DataGridSelectionMode.None;
    [Parameter] public DataGridEditMode EditMode { get; set; } = DataGridEditMode.None;
    [Parameter] public int PageSize { get; set; } = 10;
    [Parameter] public bool ShowPagination { get; set; } = true;
    [Parameter] public bool ShowToolbar { get; set; }

    /// <summary>Show the global search box in the toolbar. Default true.</summary>
    [Parameter] public bool ShowSearch { get; set; } = true;

    /// <summary>Show the Columns button (visibility/reorder menu). Default true.</summary>
    [Parameter] public bool ShowColumnChooser { get; set; } = true;

    /// <summary>
    /// Show the Export button and its format dropdown. Default true.
    /// Set false to hide export entirely. For fine-grained per-format control see
    /// <see cref="ExportFormats"/>.
    /// </summary>
    [Parameter] public bool ShowExport { get; set; } = true;

    /// <summary>
    /// Which export formats appear in the Export dropdown. Default <see cref="DataGridExportFormat.All"/>.
    /// Set to e.g. <c>Csv | Excel</c> to hide PDF in WebAssembly where QuestPDF isn't supported.
    /// When no flags are set (or <see cref="ShowExport"/> is false), the Export button is hidden.
    /// </summary>
    [Parameter] public DataGridExportFormat ExportFormats { get; set; } = DataGridExportFormat.All;
    [Parameter] public int VirtualizeThreshold { get; set; } = 500;
    [Parameter] public bool Reorderable { get; set; }
    [Parameter] public bool RowReorderable { get; set; }
    [Parameter] public string? GroupBy { get; set; }
    [Parameter] public bool GroupsExpandedByDefault { get; set; } = true;

    // --- Fullscreen / Expandable ---
    /// <summary>
    /// When true, adds a small Expand icon to the toolbar. Clicking it
    /// renders the grid in a fullscreen modal overlay. Default false.
    /// </summary>
    [Parameter] public bool Expandable { get; set; }

    /// <summary>
    /// When true, the grid is currently rendered in fullscreen. Bind this
    /// for programmatic control, or leave unbound to let the grid manage
    /// its own state via the toolbar button.
    /// </summary>
    [Parameter] public bool IsExpanded { get; set; }

    [Parameter] public EventCallback<bool> IsExpandedChanged { get; set; }

    /// <summary>
    /// Optional title shown in the fullscreen header bar. Defaults to "Data Grid".
    /// </summary>
    [Parameter] public string? FullscreenTitle { get; set; }

    // --- Conditional Row Styling ---
    [Parameter] public Func<TItem, string>? RowClass { get; set; }
    [Parameter] public Func<TItem, string>? RowStyle { get; set; }

    // --- Layout Persistence ---
    [Parameter] public bool EnableLayoutPersistence { get; set; }
    [Parameter] public string? LayoutStorageKey { get; set; }
    [Parameter] public EventCallback<DataGridLayout> OnLayoutSave { get; set; }
    [Parameter] public DataGridLayout? SavedLayout { get; set; }

    // --- Named Layouts ---
    [Parameter] public List<DataGridNamedLayout>? GlobalLayouts { get; set; }
    [Parameter] public EventCallback<DataGridNamedLayout> OnSaveNamedLayout { get; set; }
    [Parameter] public EventCallback<string> OnDeleteNamedLayout { get; set; }

    // --- Server mode ---
    [Parameter] public bool ServerMode { get; set; }
    [Parameter] public EventCallback<DataGridServerRequest> OnServerRequest { get; set; }
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public bool IsLoading { get; set; }

    // --- Templates ---
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public RenderFragment<TItem>? DetailTemplate { get; set; }
    [Parameter] public RenderFragment? EmptyContent { get; set; }
    [Parameter] public RenderFragment<TItem>? RowContextMenu { get; set; }

    // --- Events ---
    [Parameter] public EventCallback<TItem> OnRowClick { get; set; }
    [Parameter] public EventCallback<TItem> OnRowDoubleClick { get; set; }
    [Parameter] public EventCallback<CellEditEventArgs<TItem>> OnCellEdit { get; set; }
    [Parameter] public EventCallback<RowEditEventArgs<TItem>> OnRowEdit { get; set; }
    [Parameter] public EventCallback<ColumnReorderEventArgs> OnColumnReorder { get; set; }
    [Parameter] public EventCallback<RowReorderEventArgs<TItem>> OnRowReorder { get; set; }
    [Parameter] public EventCallback<Exception> OnError { get; set; }
    [Parameter] public IReadOnlyList<TItem>? SelectedItems { get; set; }
    [Parameter] public EventCallback<IReadOnlyList<TItem>> SelectedItemsChanged { get; set; }

    // --- Standard ---
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Inject ---
    [Inject] private ComponentInteropService Interop { get; set; } = default!;
    [Inject] private Lumeo.Services.IDataGridExportService Export { get; set; } = default!;

    // --- Culture ---
    /// <summary>
    /// CultureInfo used for cell value formatting (dates/numbers) and exports.
    /// When null (default), falls back to <see cref="System.Globalization.CultureInfo.CurrentCulture"/>.
    /// Useful when your app sets a different culture than the UI locale — e.g. force
    /// <c>de-DE</c> formatting in an English UI.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    internal System.Globalization.CultureInfo EffectiveCulture =>
        Culture ?? System.Globalization.CultureInfo.CurrentCulture;

    // --- Internal state ---
    private List<DataGridColumn<TItem>> _columnDefs = new();
    private List<DataGridColumn<TItem>> _orderedColumns = new();
    private List<TItem> _processedItems = new();
    private List<TItem> _displayedItems = new();
    private List<TItem> _selectedItems = new();
    private HashSet<TItem> _selectedSet = new();
    private HashSet<TItem> _expandedRows = new();
    private HashSet<TItem> _editingRows = new();
#pragma warning disable CS8714
    private Dictionary<TItem, Dictionary<string, object?>> _rowEditValues = new();
#pragma warning restore CS8714
    private List<SortDescriptor> _sorts = new();
    private List<FilterDescriptor> _filters = new();
    private string? _globalSearch;
    private int _currentPage = 1;
    private string? _activeFilterColumn;
    private bool _contextMenuVisible;
    private double _contextMenuX;
    private double _contextMenuY;
    private TItem? _contextMenuItem;
    private string _contextMenuId = $"dg-ctx-{Guid.NewGuid():N}";
    private bool _isExpanded;
    private bool _lastIsExpandedParam;
    private bool _fullscreenNeedsFocus;
    private ElementReference _fullscreenRef;
    private List<DataGridGroupSection<TItem>> _groupedSections = new();
    private HashSet<string> _expandedGroups = new();
    private HashSet<string> _knownGroupKeys = new();
    private string? _lastGroupBy;
    private bool? _lastGroupsExpandedByDefault;
    private string _layoutId = $"datagrid-{Guid.NewGuid():N}";
    private DataGridLayout? _defaultLayout; // snapshot of original column state for reset
    private bool _savedLayoutApplied; // tracks whether the SavedLayout parameter has been applied
    private DataGridLayoutService? _layoutService;
    private DataGridServerService? _serverService;
    private DataGridToolbarContext<TItem> _toolbarContext = new();

    /// <summary>
    /// Stable per-instance id used to scope drag state. Allocated once per
    /// grid instance and cascaded via <see cref="DataGridDragState"/> so
    /// header cells / rows can reject drops that originated in a different
    /// grid instance on the same page.
    /// </summary>
    private readonly string _gridInstanceId = Guid.NewGuid().ToString("N");
    private readonly DataGridDragState _dragState;

    public DataGrid()
    {
        _dragState = new DataGridDragState(_gridInstanceId);
    }

    // --- ToolbarContent component registration ---

    /// <summary>
    /// The <see cref="ToolbarContent{TItem}"/> component currently registered inside
    /// this grid (at most one). Forwarded to <see cref="DataGridToolbar"/> so it can
    /// render the custom ChildContent + Class in the toolbar's left-hand slot.
    /// </summary>
    internal ToolbarContent<TItem>? RegisteredToolbarContent { get; private set; }

    internal void RegisterToolbarContent(ToolbarContent<TItem> tc)
    {
        // Re-registration from the child's OnParametersSet happens on every render;
        // only flag a re-render when the instance actually changed, otherwise we'd
        // loop (StateHasChanged → child re-renders → re-registers → StateHasChanged).
        // Class/ChildContent updates on the SAME instance are already read by the
        // next natural parent render (we dereference them at render time).
        if (!ReferenceEquals(RegisteredToolbarContent, tc))
        {
            RegisteredToolbarContent = tc;
            InvokeAsync(StateHasChanged);
        }
    }

    internal void UnregisterToolbarContent(ToolbarContent<TItem> tc)
    {
        if (RegisteredToolbarContent == tc)
        {
            RegisteredToolbarContent = null;
            InvokeAsync(StateHasChanged);
        }
    }

    private List<DataGridColumn<TItem>> SourceColumns =>
        Columns is not null && Columns.Count > 0 ? Columns : _columnDefs;

    private List<DataGridColumn<TItem>> EffectiveColumns =>
        _orderedColumns.Count > 0 ? _orderedColumns : SourceColumns;

    private int EffectiveTotalCount => ServerMode ? TotalCount : _processedItems.Count;

    private bool UseVirtualization => _displayedItems.Count > VirtualizeThreshold;

    private string? HeightStyle => Height is not null ? $"height: {Height};" : null;

    private string RootCssClass
    {
        get
        {
            return string.Join(" ", new[]
            {
                "w-full overflow-auto border border-border/40 rounded-lg bg-card text-card-foreground flex flex-col",
                Compact ? "text-sm" : null,
                Bordered ? "[&_td]:border [&_td]:border-border/40 [&_th]:border [&_th]:border-border/40" : null,
                Striped ? "[&_tbody>tr:nth-child(even)]:bg-muted/30" : null,
                Class
            }.Where(s => !string.IsNullOrWhiteSpace(s)));
        }
    }

    /// <summary>
    /// Registers a column definition with the grid. Idempotent: if a column with
    /// the same stable key (Field when available, else Id) is already registered
    /// the existing entry is replaced in-place. This matters because Blazor can
    /// re-initialize <see cref="DataGridColumnDef{TItem}"/> children on every
    /// parent render when the ChildContent is captured inside a RenderFragment
    /// local — without this dedup the column list would accumulate duplicates
    /// (causing the filter popover to open N times, the "Toggle Columns" menu
    /// to list every column N times, etc.).
    /// </summary>
    public void AddColumnDef(DataGridColumn<TItem> column)
    {
        var key = ColumnKey(column);
        var existingIndex = _columnDefs.FindIndex(c => ColumnKey(c) == key);
        if (existingIndex >= 0)
        {
            // Preserve user-mutable state on the existing column object so a
            // re-init from the razor child doesn't blow away width/visibility/pin.
            var existing = _columnDefs[existingIndex];
            existing.Title = column.Title;
            existing.Field = column.Field;
            existing.FieldSelector = column.FieldSelector;
            existing.Sortable = column.Sortable;
            existing.Filterable = column.Filterable;
            existing.Resizable = column.Resizable;
            existing.FilterType = column.FilterType;
            existing.Aggregate = column.Aggregate;
            existing.Format = column.Format;
            existing.CellTemplate = column.CellTemplate;
            existing.HeaderTemplate = column.HeaderTemplate;
            existing.EditTemplate = column.EditTemplate;
            existing.FilterOptions = column.FilterOptions;
            existing.Operators = column.Operators;
            existing.FilterTemplate = column.FilterTemplate;
            existing.MinWidth = column.MinWidth;
            existing.MaxWidth = column.MaxWidth;
            existing.Pinnable = column.Pinnable;
            existing.Groupable = column.Groupable;
            existing.Reorderable = column.Reorderable;
            existing.CellClass = column.CellClass;
            existing.HeaderCssClass = column.HeaderCssClass;
            existing.CustomSort = column.CustomSort;
            existing.CssClass = column.CssClass;
            // Only apply width/pin from the redeclared column if the user has
            // not customised them at runtime (e.g. via resize/toggle).
            if (!existing.Visible && column.Visible) { /* keep user hidden */ }
            return;
        }

        _columnDefs.Add(column);
        SyncOrderedColumns();
        // DataGridColumnDef children register themselves from their own
        // OnInitialized, which runs AFTER the parent has already built its
        // render tree with an empty column list. Without this nudge the
        // header + body render blank until some other state change retriggers
        // a render. InvokeAsync defers the re-render to the next dispatcher
        // cycle so we don't recurse during the child's init.
        _ = InvokeAsync(StateHasChanged);
    }

    /// <summary>
    /// Removes a previously-registered column definition (called when a
    /// <see cref="DataGridColumnDef{TItem}"/> child is disposed).
    /// </summary>
    public void RemoveColumnDef(DataGridColumn<TItem> column)
    {
        var key = ColumnKey(column);
        var removed = _columnDefs.RemoveAll(c => ColumnKey(c) == key) > 0;
        if (removed)
        {
            _orderedColumns.RemoveAll(c => ColumnKey(c) == key);
            _ = InvokeAsync(StateHasChanged);
        }
    }

    /// <summary>Stable identity for a column: prefer Field (user-declared), fallback to Id.</summary>
    private static string ColumnKey(DataGridColumn<TItem> column) =>
        !string.IsNullOrWhiteSpace(column.Field) ? column.Field! : column.Id;

    public void UpdateColumnWidth(string columnId, double width)
    {
        var column = EffectiveColumns.FirstOrDefault(c => c.Id == columnId);
        if (column is not null)
        {
            column.Width = Math.Max(column.MinWidth ?? 50, width);
            if (column.MaxWidth.HasValue)
                column.Width = Math.Min(column.MaxWidth.Value, column.Width.Value);
            ScheduleAutoSave();
            StateHasChanged();
        }
    }

    private void SyncOrderedColumns()
    {
        var source = SourceColumns;

        // If ordered columns has different column set (by ID), rebuild from source
        // Preserve user-reordered order for existing columns
        var sourceIds = source.Select(c => c.Id).ToHashSet();
        var orderedIds = _orderedColumns.Select(c => c.Id).ToHashSet();

        if (sourceIds.SetEquals(orderedIds)) return; // Same columns, keep user order

        // Columns changed — rebuild keeping existing order for known columns, append new ones
        var newOrder = _orderedColumns.Where(c => sourceIds.Contains(c.Id)).ToList();
        var added = source.Where(c => !orderedIds.Contains(c.Id)).ToList();
        newOrder.AddRange(added);
        _orderedColumns = newOrder;
    }

    protected override async Task OnParametersSetAsync()
    {
        // Sync IsExpanded parameter with internal state (allow external binding to drive it)
        if (IsExpanded != _lastIsExpandedParam)
        {
            _lastIsExpandedParam = IsExpanded;
            if (_isExpanded != IsExpanded)
            {
                _isExpanded = IsExpanded;
                if (_isExpanded)
                {
                    _fullscreenNeedsFocus = true;
                    try { await Interop.LockScroll(); } catch { /* best-effort */ }
                }
                else
                {
                    try { await Interop.UnlockScroll(); } catch { /* best-effort */ }
                }
            }
        }

        SyncOrderedColumns();

        // Snapshot default layout once (before any external SavedLayout is applied)
        if (_defaultLayout is null && EffectiveColumns.Count > 0)
        {
            _defaultLayout = SnapshotCurrentLayout();
        }

        // Apply SavedLayout when provided externally and not yet applied
        if (SavedLayout is not null && !_savedLayoutApplied)
        {
            _savedLayoutApplied = true;
            await ApplyLayoutAsync(SavedLayout);
            return; // ApplyLayoutAsync calls ProcessClientData
        }

        if (ServerMode)
        {
            _displayedItems = Items?.ToList() ?? new List<TItem>();

            // Apply client-side grouping on server-returned items when GroupBy is set
            if (!string.IsNullOrEmpty(GroupBy) && _displayedItems.Count > 0)
            {
                var groupCol = EffectiveColumns.FirstOrDefault(c => c.Field == GroupBy);
                if (groupCol is not null)
                {
                    var serverGroupByChanged = GroupBy != _lastGroupBy;
                    _lastGroupBy = GroupBy;

                    _groupedSections = _displayedItems
                        .GroupBy(item => groupCol.GetFormattedValue(item))
                        .OrderBy(g => g.Key)
                        .Select(g => new DataGridGroupSection<TItem>(g.Key, g.ToList(), g.Count()))
                        .ToList();

                    var serverDefaultChanged = _lastGroupsExpandedByDefault is not null && _lastGroupsExpandedByDefault != GroupsExpandedByDefault;
                    _lastGroupsExpandedByDefault = GroupsExpandedByDefault;

                    if (serverGroupByChanged || serverDefaultChanged)
                    {
                        _expandedGroups.Clear();
                        _knownGroupKeys.Clear();
                        foreach (var section in _groupedSections)
                        {
                            _knownGroupKeys.Add(section.Key);
                            if (GroupsExpandedByDefault)
                                _expandedGroups.Add(section.Key);
                        }
                    }
                    else
                    {
                        var validKeys = _groupedSections.Select(s => s.Key).ToHashSet();
                        _expandedGroups.IntersectWith(validKeys);
                        _knownGroupKeys.IntersectWith(validKeys);
                        foreach (var section in _groupedSections)
                        {
                            if (_knownGroupKeys.Contains(section.Key)) continue;
                            _knownGroupKeys.Add(section.Key);
                            if (GroupsExpandedByDefault)
                                _expandedGroups.Add(section.Key);
                        }
                    }
                }
            }
            else
            {
                _lastGroupBy = null;
            }
        }
        else
        {
            ProcessClientData();
        }

        if (SelectedItems is not null)
        {
            _selectedItems = SelectedItems.ToList();
            _selectedSet = new HashSet<TItem>(_selectedItems);
        }

        PopulateToolbarContext();
    }

    /// <summary>
    /// Rebuilds the cascading <see cref="DataGridToolbarContext{TItem}"/> used by the
    /// extracted toolbar tool components (Fullscreen, CopySelected, Columns, Export,
    /// Layouts) as well as any custom tools placed inside <see cref="ToolbarContent{TItem}"/>.
    /// Called from OnParametersSetAsync so dependent values reflect the latest parameters.
    /// </summary>
    private void PopulateToolbarContext()
    {
        _toolbarContext.IsExpanded = _isExpanded;
        _toolbarContext.Expandable = Expandable;
        _toolbarContext.OnToggleExpanded = EventCallback.Factory.Create(this, ToggleExpanded);

        _toolbarContext.SelectedItems = _selectedItems;
        _toolbarContext.EffectiveColumns = EffectiveColumns.AsReadOnly();
        _toolbarContext.OnColumnToggle = EventCallback.Factory.Create<DataGridColumn<TItem>>(this, HandleColumnVisibilityChanged);
        _toolbarContext.OnColumnReorder = EventCallback.Factory.Create<ColumnReorderEventArgs>(this, HandleColumnReorder);

        _toolbarContext.ExportFormats = ExportFormats;
        _toolbarContext.OnExport = EventCallback.Factory.Create<string>(this, HandleExport);

        _toolbarContext.EnableLayoutPersistence = EnableLayoutPersistence;
        _toolbarContext.GlobalLayouts = GlobalLayouts;
        _toolbarContext.OnSaveLayout = EventCallback.Factory.Create(this, HandleSaveLayout);
        _toolbarContext.OnResetLayout = EventCallback.Factory.Create(this, HandleResetLayout);
        _toolbarContext.OnSaveNamedLayout = EventCallback.Factory.Create<DataGridNamedLayout>(this, HandleSaveNamedLayout);
        _toolbarContext.OnDeleteNamedLayout = OnDeleteNamedLayout;
        _toolbarContext.OnApplyNamedLayout = EventCallback.Factory.Create<DataGridNamedLayout>(this, HandleApplyNamedLayout);
        _toolbarContext.LayoutStorageKey = LayoutStorageKey;
        _toolbarContext.OnError = OnError;

        _toolbarContext.Interop = Interop;
        _toolbarContext.Localizer = L;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _layoutService ??= new DataGridLayoutService(Interop, ex =>
            {
                if (OnError.HasDelegate)
                    InvokeAsync(() => OnError.InvokeAsync(ex));
            });
            _serverService ??= new DataGridServerService();

            // Snapshot default layout now that columns are registered (via ColumnDef)
            if (_defaultLayout is null && EffectiveColumns.Count > 0)
            {
                _defaultLayout = SnapshotCurrentLayout();
            }

            if (EnableLayoutPersistence && !_layoutService.LayoutLoaded)
            {
                var key = LayoutStorageKey ?? _layoutId;
                await _layoutService.LoadPersistedLayoutAsync(key, ApplyLayoutAsync);
            }
        }

        if (_isExpanded && _fullscreenNeedsFocus)
        {
            _fullscreenNeedsFocus = false;
            try { await _fullscreenRef.FocusAsync(); } catch { /* element may not be ready */ }
        }
    }

    /// <summary>
    /// Toggles fullscreen expand mode for the grid. No-op when Expandable is false.
    /// Preserves grid state (selection, filters, sorts, pagination) across the transition
    /// because the underlying grid markup is rendered as the same render-tree sub-tree.
    /// </summary>
    public async Task ToggleExpanded()
    {
        _isExpanded = !_isExpanded;
        _lastIsExpandedParam = _isExpanded;
        IsExpanded = _isExpanded;

        if (_isExpanded)
        {
            _fullscreenNeedsFocus = true;
            try { await Interop.LockScroll(); } catch { /* best-effort */ }
            try { await Interop.SetHtmlClass("lumeo-fullscreen-active", true); } catch { /* best-effort */ }
        }
        else
        {
            try { await Interop.UnlockScroll(); } catch { /* best-effort */ }
            try { await Interop.SetHtmlClass("lumeo-fullscreen-active", false); } catch { /* best-effort */ }
        }

        if (IsExpandedChanged.HasDelegate)
            await IsExpandedChanged.InvokeAsync(_isExpanded);

        // Rebuild the cascading toolbar context so DataGridToolbarFullscreen sees the updated
        // IsExpanded and swaps its Maximize2/Minimize2 icon. Without this, the context was
        // only refreshed on parameter changes and the fullscreen icon stayed stale.
        PopulateToolbarContext();
        StateHasChanged();
    }

    private async Task HandleFullscreenKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && _isExpanded)
        {
            await ToggleExpanded();
        }
    }

    protected override async Task OnInitializedAsync()
    {
        _layoutService ??= new DataGridLayoutService(Interop, ex =>
        {
            if (OnError.HasDelegate)
                InvokeAsync(() => OnError.InvokeAsync(ex));
        });
        _serverService ??= new DataGridServerService();

        if (ServerMode)
        {
            await RequestServerData();
        }
    }

    private void ProcessClientData()
    {
        if (Items is null)
        {
            _processedItems = new List<TItem>();
            _displayedItems = new List<TItem>();
            return;
        }

        // Clean stale selections that reference items no longer in the data source
        if (_selectedItems.Count > 0)
        {
            var currentItems = new HashSet<TItem>(Items);
            var staleCount = _selectedItems.RemoveAll(item => !currentItems.Contains(item));
            if (staleCount > 0)
            {
                _selectedSet = new HashSet<TItem>(_selectedItems);
                NotifySelectionChanged();
            }
        }

        var query = Items.AsEnumerable();

        // Global search
        if (!string.IsNullOrWhiteSpace(_globalSearch))
        {
            var search = _globalSearch;
            query = query.Where(item =>
                EffectiveColumns.Any(col =>
                {
                    var value = col.GetFormattedValue(item);
                    return value.Contains(search, StringComparison.OrdinalIgnoreCase);
                }));
        }

        // Column filters
        foreach (var filter in _filters)
        {
            var column = EffectiveColumns.FirstOrDefault(c => c.Field == filter.Field);
            if (column is null) continue;

            query = query.Where(item =>
            {
                var value = column.GetValue(item);
                return DataGridFilterOperator.Evaluate(filter, value);
            });
        }

        // Sort
        IOrderedEnumerable<TItem>? ordered = null;
        foreach (var sort in _sorts.Where(s => s.Direction != SortDirection.None))
        {
            var column = EffectiveColumns.FirstOrDefault(c => c.Field == sort.Field);
            if (column is null) continue;

            if (ordered is null)
            {
                if (column.CustomSort is not null)
                {
                    var comp = column.CustomSort;
                    ordered = sort.Direction == SortDirection.Ascending
                        ? query.OrderBy(item => column.GetValue(item), Comparer<object?>.Create(comp))
                        : query.OrderByDescending(item => column.GetValue(item), Comparer<object?>.Create(comp));
                }
                else
                {
                    ordered = sort.Direction == SortDirection.Ascending
                        ? query.OrderBy(item => column.GetValue(item) as IComparable)
                        : query.OrderByDescending(item => column.GetValue(item) as IComparable);
                }
            }
            else
            {
                if (column.CustomSort is not null)
                {
                    var comp = column.CustomSort;
                    ordered = sort.Direction == SortDirection.Ascending
                        ? ordered.ThenBy(item => column.GetValue(item), Comparer<object?>.Create(comp))
                        : ordered.ThenByDescending(item => column.GetValue(item), Comparer<object?>.Create(comp));
                }
                else
                {
                    ordered = sort.Direction == SortDirection.Ascending
                        ? ordered.ThenBy(item => column.GetValue(item) as IComparable)
                        : ordered.ThenByDescending(item => column.GetValue(item) as IComparable);
                }
            }
        }

        _processedItems = (ordered as IEnumerable<TItem> ?? query).ToList();

        // Row grouping
        if (!string.IsNullOrEmpty(GroupBy))
        {
            var groupCol = EffectiveColumns.FirstOrDefault(c => c.Field == GroupBy);
            if (groupCol is not null)
            {
                var groupByChanged = GroupBy != _lastGroupBy;
                _lastGroupBy = GroupBy;

                _groupedSections = _processedItems
                    .GroupBy(item => groupCol.GetFormattedValue(item))
                    .OrderBy(g => g.Key)
                    .Select(g => new DataGridGroupSection<TItem>(g.Key, g.ToList(), g.Count()))
                    .ToList();

                var defaultChanged = _lastGroupsExpandedByDefault is not null && _lastGroupsExpandedByDefault != GroupsExpandedByDefault;
                _lastGroupsExpandedByDefault = GroupsExpandedByDefault;

                if (groupByChanged || defaultChanged)
                {
                    // GroupBy field or default toggle changed — reset expand state based on default
                    _expandedGroups.Clear();
                    _knownGroupKeys.Clear();
                    foreach (var section in _groupedSections)
                    {
                        _knownGroupKeys.Add(section.Key);
                        if (GroupsExpandedByDefault)
                            _expandedGroups.Add(section.Key);
                    }
                }
                else
                {
                    // Keep user's expand/collapse state; remove stale keys
                    var validKeys = _groupedSections.Select(s => s.Key).ToHashSet();
                    _expandedGroups.IntersectWith(validKeys);
                    _knownGroupKeys.IntersectWith(validKeys);
                    // Apply default only to groups we haven't seen before (not to user-toggled ones)
                    foreach (var section in _groupedSections)
                    {
                        if (_knownGroupKeys.Contains(section.Key)) continue;
                        _knownGroupKeys.Add(section.Key);
                        if (GroupsExpandedByDefault)
                            _expandedGroups.Add(section.Key);
                    }
                }

                // When grouped, show items from expanded groups (no pagination)
                _displayedItems = _groupedSections
                    .Where(g => _expandedGroups.Contains(g.Key))
                    .SelectMany(g => g.Items)
                    .ToList();
                return; // Skip normal pagination when grouped
            }
        }
        _lastGroupBy = null;
        _groupedSections.Clear();

        // Paginate
        if (ShowPagination && PageSize > 0)
        {
            var totalPages = Math.Max(1, (int)Math.Ceiling((double)_processedItems.Count / PageSize));
            if (_currentPage > totalPages) _currentPage = totalPages;
            if (_currentPage < 1) _currentPage = 1;

            _displayedItems = _processedItems
                .Skip((_currentPage - 1) * PageSize)
                .Take(PageSize)
                .ToList();
        }
        else
        {
            _displayedItems = _processedItems;
        }
    }

    private async Task HandleSort(SortDescriptor sort)
    {
        _sorts.RemoveAll(s => s.Field == sort.Field);
        if (sort.Direction != SortDirection.None)
        {
            _sorts.Add(sort);
        }

        _currentPage = 1;
        ScheduleAutoSave();

        if (ServerMode)
        {
            await RequestServerData();
        }
        else
        {
            ProcessClientData();
        }
    }

    private async Task HandleFilter(FilterDescriptor filter)
    {
        _filters.RemoveAll(f => f.Field == filter.Field);
        _filters.Add(filter);
        _currentPage = 1;
        ScheduleAutoSave();

        if (ServerMode)
        {
            await RequestServerData();
        }
        else
        {
            ProcessClientData();
        }
    }

    private async Task RemoveFilter(FilterDescriptor filter)
    {
        _filters.RemoveAll(f => f.Field == filter.Field);
        _currentPage = 1;
        ScheduleAutoSave();

        if (ServerMode)
        {
            await RequestServerData();
        }
        else
        {
            ProcessClientData();
        }
    }

    private async Task HandleGlobalSearch(string search)
    {
        _globalSearch = string.IsNullOrWhiteSpace(search) ? null : search;
        _currentPage = 1;
        ScheduleAutoSave();

        if (ServerMode)
        {
            _serverService!.DebounceSearch(async ct =>
            {
                if (ct.IsCancellationRequested) return;
                await InvokeAsync(async () =>
                {
                    await RequestServerData();
                    StateHasChanged();
                });
            });
        }
        else
        {
            ProcessClientData();
            StateHasChanged();
        }
    }

