    private bool IsRowSelected(TItem item) => _selectedSet.Contains(item);

    private bool IsRowExpanded(TItem item) => _expandedRows.Contains(item);

    private bool IsRowEditing(TItem item) => _editingRows.Contains(item);

    private void ToggleSelection(TItem item)
    {
        if (SelectionMode == DataGridSelectionMode.Single)
        {
            var wasSelected = _selectedSet.Contains(item);
            _selectedSet.Clear();
            _selectedItems.Clear();

            if (!wasSelected)
            {
                _selectedSet.Add(item);
                _selectedItems.Add(item);
            }
        }
        else if (SelectionMode == DataGridSelectionMode.Multiple)
        {
            if (_selectedSet.Contains(item))
            {
                _selectedSet.Remove(item);
                _selectedItems.Remove(item);
            }
            else
            {
                _selectedSet.Add(item);
                _selectedItems.Add(item);
            }
        }

        NotifySelectionChanged();
        StateHasChanged();
    }

    private void SelectAll()
    {
        _selectedItems = _displayedItems.ToList();
        _selectedSet = new HashSet<TItem>(_selectedItems);
        NotifySelectionChanged();
        StateHasChanged();
    }

    private void ClearSelection()
    {
        _selectedItems.Clear();
        _selectedSet.Clear();
        NotifySelectionChanged();
        StateHasChanged();
    }

    /// <summary>
    /// Invokes the <see cref="SelectedItemsChanged"/> EventCallback safely from sync
    /// call sites. The previous implementation discarded the returned Task; a faulting
    /// async consumer handler would surface as an UnobservedTaskException AND the parent
    /// re-render after <see cref="StateHasChanged"/> could race a still-running consumer
    /// callback. <see cref="Lumeo.Services.SafeAsyncDispatcher.FireAndForget"/> dispatches
    /// the InvokeAsync via the component's renderer, swallows lifecycle-class
    /// exceptions silently, and logs anything unexpected with a structured tag.
    /// </summary>
    private void NotifySelectionChanged()
    {
        if (!SelectedItemsChanged.HasDelegate) return;
        var snapshot = _selectedItems.AsReadOnly();
        Lumeo.Services.SafeAsyncDispatcher.FireAndForget(
            InvokeAsync,
            () => SelectedItemsChanged.InvokeAsync(snapshot),
            "DataGrid.SelectionChanged");
    }

    private void ToggleGroupExpand(string key)
