    }

    // --- Row Editing ---

    private void StartRowEdit(TItem item)
    {
        if (_editingRows.Contains(item)) return;
        _editingRows.Add(item);
        // Snapshot current values for all editable columns
        var editDict = new Dictionary<string, object?>();
        foreach (var col in EffectiveColumns.Where(c => c.Field is not null))
        {
            editDict[col.Field!] = col.GetValue(item);
        }
        _rowEditValues[item] = editDict;
        StateHasChanged();
    }

    private void CancelRowEdit(TItem item)
    {
        _editingRows.Remove(item);
        _rowEditValues.Remove(item);
        StateHasChanged();
    }

    private async Task CommitRowEditAsync(TItem item)
    {
        if (!_editingRows.Contains(item)) return;
        _editingRows.Remove(item);

        if (_rowEditValues.TryGetValue(item, out var editDict))
        {
            _rowEditValues.Remove(item);
            if (OnRowEdit.HasDelegate)
            {
                await OnRowEdit.InvokeAsync(new RowEditEventArgs<TItem>(item, editDict));
            }
        }
        StateHasChanged();
    }

    private object? GetEditValue(TItem item, DataGridColumn<TItem> column)
    {
        if (column.Field is null) return null;
        if (_rowEditValues.TryGetValue(item, out var dict) && dict.TryGetValue(column.Field, out var val))
            return val;
        return column.GetValue(item);
    }

    private void SetEditValue(TItem item, DataGridColumn<TItem> column, object? value)
    {
        if (column.Field is null) return;
        if (!_rowEditValues.ContainsKey(item))
            _rowEditValues[item] = new Dictionary<string, object?>();
        _rowEditValues[item][column.Field] = value;
    }

    // --- Column Reordering ---

    private async Task HandleColumnReorder(ColumnReorderEventArgs args)
    {
        if (args.OldIndex < 0 || args.NewIndex < 0 || args.OldIndex >= _orderedColumns.Count || args.NewIndex >= _orderedColumns.Count)
            return;

        var col = _orderedColumns[args.OldIndex];
        _orderedColumns.RemoveAt(args.OldIndex);
        _orderedColumns.Insert(args.NewIndex, col);

        // Await consumer handler so async handlers complete before we re-render.
        // Previously the returned Task was discarded which let the next
        // StateHasChanged race a still-running consumer callback and let
        // exceptions in async handlers go unobserved.
        if (OnColumnReorder.HasDelegate)
            await OnColumnReorder.InvokeAsync(args);

        ScheduleAutoSave();
        StateHasChanged();
    }

    // --- Row Reordering ---

    public void MoveRow(int oldIndex, int newIndex)
    {
        if (oldIndex < 0 || newIndex < 0 || oldIndex >= _displayedItems.Count || newIndex >= _displayedItems.Count)
            return;

        var item = _displayedItems[oldIndex];
        _displayedItems.RemoveAt(oldIndex);
        _displayedItems.Insert(newIndex, item);

        // Public sync API — can't change return type without breaking consumers.
        // Dispatch the consumer callback through SafeAsyncDispatcher so faults
        // in async handlers are observed (logged) instead of becoming
        // UnobservedTaskExceptions, and so a faulting outer InvokeAsync (e.g.
        // disposed renderer) is also handled.
        if (OnRowReorder.HasDelegate)
        {
            var args = new RowReorderEventArgs<TItem>(item, oldIndex, newIndex);
            Lumeo.Services.SafeAsyncDispatcher.FireAndForget(
                InvokeAsync,
                () => OnRowReorder.InvokeAsync(args),
                "DataGrid.RowReorder");
        }

        StateHasChanged();
    }

