    private async Task HandleFilterApply(FilterApplyEventArgs args)
    {
        if (args.Filter is not null)
        {
            await HandleFilter(args.Filter);
        }
        else if (args.Field is not null)
        {
            var existing = _filters.FirstOrDefault(f => f.Field == args.Field);
