    }

    private async Task HandleExport(string format)
    {
        var items = ServerMode ? _displayedItems : _processedItems;
        var culture = EffectiveCulture;
        var visibleColumns = EffectiveColumns.Where(c => c.Visible).ToList();
        var exportColumns = visibleColumns.Select(c => new Lumeo.Services.DataGridExportColumn<TItem>(
            Header: c.Title ?? c.Field ?? c.Id,
            Accessor: row => c.GetValue(row),
            Format: c.Format
        )).ToList();

        try
        {
            switch (format)
            {
                case "json":
                    // JSON uses the formatted (culture-aware) string representation per column
                    // so consumers get a row shape that mirrors the visible grid.
                    {
                        var rows = items.Select(item =>
                        {
                            var dict = new Dictionary<string, string?>();
                            foreach (var col in visibleColumns)
                            {
                                var key = col.Title ?? col.Field ?? col.Id;
                                dict[key] = col.GetFormattedValue(item, culture);
                            }
                            return dict;
                        }).ToList();
                        var json = System.Text.Json.JsonSerializer.Serialize(rows, new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
                        var bytes = System.Text.Encoding.UTF8.GetBytes(json);
                        await Export.DownloadAsync(bytes, "export.json", "application/json");
                        break;
                    }
                case "excel":
                    {
                        var bytes = Export.ToExcel(items, exportColumns, sheetName: "Data", culture: culture);
                        await Export.DownloadAsync(bytes, "export.xlsx",
                            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
                        break;
                    }
                case "pdf":
                    {
                        // QuestPDF isn't supported on browser-wasm — ToPdf throws PlatformNotSupportedException
                        // on that runtime. Consumers should restrict ExportFormats to exclude Pdf on WASM.
                        var bytes = Export.ToPdf(items, exportColumns, title: FullscreenTitle ?? "Export", culture: culture);
                        await Export.DownloadAsync(bytes, "export.pdf", "application/pdf");
                        break;
                    }
                default:
                    {
                        var bytes = Export.ToCsv(items, exportColumns, culture: culture);
                        await Export.DownloadAsync(bytes, "export.csv", "text/csv; charset=utf-8");
                        break;
                    }
            }
        }
        catch (Exception ex) when (OnError.HasDelegate)
        {
            await OnError.InvokeAsync(ex);
        }
    }

    // --- Layout Persistence ---

    public DataGridLayout GetCurrentLayout() => SnapshotCurrentLayout();

    private DataGridLayout SnapshotCurrentLayout()
    {
        var cols = _orderedColumns.Select((c, i) => new ColumnLayout
        {
            Field = c.Field ?? c.Id,
            Width = c.Width,
            Visible = c.Visible,
            Pin = c.Pin,
            Order = i
        }).ToList();

        return new DataGridLayout
        {
            Columns = cols,
            Sorts = _sorts.Count > 0 ? new List<SortDescriptor>(_sorts) : null,
            Filters = _filters.Count > 0 ? new List<FilterDescriptor>(_filters) : null,
            PageSize = PageSize,
            GlobalSearch = _globalSearch
        };
    }

    public async Task ApplyLayoutAsync(DataGridLayout layout)
    {
        // Restore column order, width, visibility, pin
        if (layout.Columns.Count > 0)
        {
            // Build a lookup from field → column object
            var colByField = EffectiveColumns.ToDictionary(c => c.Field ?? c.Id);

            var ordered = layout.Columns
                .OrderBy(cl => cl.Order)
                .Select(cl =>
                {
                    if (!colByField.TryGetValue(cl.Field, out var col)) return null;
                    col.Visible = cl.Visible;
                    col.Pin = cl.Pin;
                    if (cl.Width.HasValue) col.Width = cl.Width;
                    return col;
                })
                .Where(c => c is not null)
                .Select(c => c!)
                .ToList();

            // Append any columns not included in layout (new columns added since last save)
            var layoutFields = layout.Columns.Select(cl => cl.Field).ToHashSet();
            var missing = EffectiveColumns.Where(c => !layoutFields.Contains(c.Field ?? c.Id));
            ordered.AddRange(missing);

            _orderedColumns = ordered;
        }

        // Restore sorts
        _sorts = layout.Sorts is not null ? new List<SortDescriptor>(layout.Sorts) : new List<SortDescriptor>();

        // Restore filters
        _filters = layout.Filters is not null ? new List<FilterDescriptor>(layout.Filters) : new List<FilterDescriptor>();

        // Restore page size
        if (layout.PageSize.HasValue)
            PageSize = layout.PageSize.Value;

        // Restore global search
        _globalSearch = layout.GlobalSearch;

        _currentPage = 1;

        if (ServerMode)
            await RequestServerData();
        else
            ProcessClientData();

        StateHasChanged();
    }

    public async Task ResetLayoutAsync()
    {
        if (_defaultLayout is not null)
        {
            await ApplyLayoutAsync(_defaultLayout);
        }
        else
        {
            // No snapshot — restore ordering from effective columns
            _orderedColumns = new List<DataGridColumn<TItem>>(EffectiveColumns);
            foreach (var col in _orderedColumns)
            {
                col.Visible = true;
                col.Pin = PinDirection.None;
                col.Width = null;
            }
            _sorts.Clear();
            _filters.Clear();
            _globalSearch = null;
            PageSize = 10;
            _currentPage = 1;
            ProcessClientData();
            StateHasChanged();
        }

        if (EnableLayoutPersistence)
        {
            var key = LayoutStorageKey ?? _layoutId;
            await _layoutService!.ClearPersistedAsync(key);
        }
    }

    private void ScheduleAutoSave()
    {
        if (!EnableLayoutPersistence && !OnLayoutSave.HasDelegate) return;
        var gen = _layoutService!.CurrentSaveGeneration;
        _layoutService.ScheduleAutoSave(async () =>
        {
            await InvokeAsync(() => PersistLayoutAsync(gen + 1));
        });
    }

    private async Task PersistLayoutAsync(int? generation = null)
    {
        // Generation guard — gates BOTH the LocalStorage write AND the consumer callback.
        // Without this, a stale debounced timer could deliver an outdated layout snapshot to
        // OnLayoutSave even when the in-service guard correctly suppressed the LocalStorage write.
        if (generation.HasValue && _layoutService is not null && generation.Value != _layoutService.CurrentSaveGeneration)
            return;

        var layout = SnapshotCurrentLayout();

        if (EnableLayoutPersistence)
        {
            var key = LayoutStorageKey ?? _layoutId;
            await _layoutService!.PersistAsync(key, layout, generation);
        }

        if (OnLayoutSave.HasDelegate)
        {
            // Generation guard above ensures we don't deliver stale snapshots to the consumer's backend.
            await OnLayoutSave.InvokeAsync(layout);
        }
    }

    // --- Toolbar layout actions ---

    private async Task HandleSaveLayout()
    {
        await PersistLayoutAsync();
    }

    private async Task HandleResetLayout()
    {
        await ResetLayoutAsync();
    }

    // --- Named Layout Handlers ---

    private async Task HandleSaveNamedLayout(DataGridNamedLayout namedLayout)
    {
        var layout = SnapshotCurrentLayout();
        var withLayout = namedLayout with { Layout = layout };

        if (namedLayout.Scope == "Personal")
        {
            var namedKey = (LayoutStorageKey ?? _layoutId) + "-named";
            var existing = await _layoutService!.GetPersonalLayoutsAsync(namedKey);
            existing.Add(withLayout);
            await _layoutService.SaveNamedLayoutsAsync(namedKey, existing);
        }

