    {
        var key = (LayoutStorageKey ?? _layoutId) + "-named";
        return await _layoutService!.GetPersonalLayoutsAsync(key);
    }

    // --- Public JSON Layout API -----------------------------------------------
    //
    // These methods let dev consumers persist the grid's layout to any backend
    // (database, file, REST API) by treating a JSON string as the canonical
    // transport format. Use via @ref:
    //
    //     <DataGrid @ref="grid" ...> ... </DataGrid>
    //     var json = grid.ExportLayout();
    //     await grid.ApplyLayoutJsonAsync(json);

    /// <summary>
    /// Snapshot schema version — bump when <see cref="DataGridLayoutSnapshot"/>
    /// changes in a breaking way.
    /// </summary>
    private const int LayoutSnapshotVersion = 1;

    /// <summary>
    /// Cached, shared JsonSerializerOptions used for every ExportLayout / ApplyLayoutJsonAsync
    /// call. Reusing the instance avoids the documented perf pitfall of creating a fresh options
    /// object per call (which rebuilds type metadata every time).
    /// </summary>
    private static readonly System.Text.Json.JsonSerializerOptions _layoutJsonOptions =
        new(System.Text.Json.JsonSerializerDefaults.Web)
        {
            WriteIndented = false,
            DefaultIgnoreCondition = System.Text.Json.Serialization.JsonIgnoreCondition.WhenWritingNull,
            Converters = { new System.Text.Json.Serialization.JsonStringEnumConverter() }
        };

    /// <summary>
    /// Serializes the current grid layout (column order, widths, visibility, pin state,
    /// sorts, filters, global search, current page, page size, group-by) to a JSON string.
    /// Dev consumers can persist this to any storage — DB, file, API. Round-trips via
    /// <see cref="ApplyLayoutJsonAsync"/>.
    /// </summary>
    public string ExportLayout()
    {
        var snapshot = BuildLayoutSnapshot();
        return System.Text.Json.JsonSerializer.Serialize(snapshot, _layoutJsonOptions);
    }

    /// <summary>
    /// Deserializes a JSON layout produced by <see cref="ExportLayout"/> and applies it.
    /// Throws <see cref="System.Text.Json.JsonException"/> on malformed input; silently
    /// ignores columns the JSON references that no longer exist on the grid.
    /// </summary>
    public async Task ApplyLayoutJsonAsync(string json)
    {
        if (string.IsNullOrWhiteSpace(json))
            throw new System.Text.Json.JsonException("Empty or null layout JSON");

        var snapshot = System.Text.Json.JsonSerializer.Deserialize<DataGridLayoutSnapshot>(json, _layoutJsonOptions)
                       ?? throw new System.Text.Json.JsonException("Deserialized layout snapshot was null");

        await ApplyLayoutSnapshotAsync(snapshot);
    }

    /// <summary>
    /// Builds a <see cref="DataGridLayoutSnapshot"/> from the grid's current state.
    /// </summary>
    internal DataGridLayoutSnapshot BuildLayoutSnapshot()
    {
        var cols = _orderedColumns.Select((c, i) => new DataGridColumnLayout(
            Field: c.Field ?? c.Id,
            Order: i,
            Visible: c.Visible,
            Width: c.Width,
            Pin: c.Pin
