        return new DataGridLayoutSnapshot(
            Version: LayoutSnapshotVersion,
            Columns: cols,
            Sorts: new List<SortDescriptor>(_sorts),
            Filters: new List<FilterDescriptor>(_filters),
            GlobalSearch: _globalSearch,
            CurrentPage: _currentPage,
            PageSize: PageSize,
            GroupBy: GroupBy
        );
    }

